Create the status bar item registry as the single source of truth for all status bar item metadata, plus a helper hook that bridges registry keys to the Zustand store.

## Files to Create

### `apps/client/src/layers/features/status/model/status-bar-registry.ts`

This file defines the registry array, types, group labels, the `useStatusBarVisibility` hook, and the `resetStatusBarPreferences` function.

```ts
import type { LucideIcon } from 'lucide-react';
import {
  FolderOpen,
  GitBranch,
  Bot,
  DollarSign,
  BarChart3,
  Shield,
  Volume2,
  RefreshCw,
  ArrowUpDown,
  Globe,
  ArrowUpCircle,
} from 'lucide-react';
import { useAppStore } from '@/layers/shared/model';

/** Union of all toggleable status bar item keys. */
export type StatusBarItemKey =
  | 'cwd'
  | 'git'
  | 'model'
  | 'cost'
  | 'context'
  | 'permission'
  | 'sound'
  | 'sync'
  | 'polling'
  | 'tunnel'
  | 'version';

/** Grouping categories for the configure popover section headers. */
export type StatusBarItemGroup = 'session' | 'controls' | 'system';

export interface StatusBarItemConfig {
  /** Unique key matching the Zustand store property suffix (e.g., 'cwd' -> showStatusBarCwd). */
  key: StatusBarItemKey;
  /** Human-readable label shown in the popover and right-click menu. */
  label: string;
  /** Short description shown as subtitle in the popover. */
  description: string;
  /** Grouping category for popover section headers. */
  group: StatusBarItemGroup;
  /** Lucide icon component for the popover row. */
  icon: LucideIcon;
  /** Default visibility state, used by the scoped reset function. */
  defaultVisible: boolean;
}

/** Human-readable labels for each group, used as section headers. */
export const GROUP_LABELS: Record<StatusBarItemGroup, string> = {
  session: 'Session Info',
  controls: 'Controls',
  system: 'System',
};

/**
 * Ordered registry of all user-toggleable status bar items.
 * Items not in this registry (connection, clients) are system-managed.
 */
export const STATUS_BAR_REGISTRY: readonly StatusBarItemConfig[] = [
  { key: 'cwd', label: 'Directory', description: 'Current working directory', group: 'session', icon: FolderOpen, defaultVisible: true },
  { key: 'git', label: 'Git Status', description: 'Branch name and change count', group: 'session', icon: GitBranch, defaultVisible: true },
  { key: 'model', label: 'Model', description: 'Selected AI model', group: 'session', icon: Bot, defaultVisible: true },
  { key: 'cost', label: 'Cost', description: 'Session cost in USD', group: 'session', icon: DollarSign, defaultVisible: true },
  { key: 'context', label: 'Context Usage', description: 'Context window utilization', group: 'session', icon: BarChart3, defaultVisible: true },
  { key: 'permission', label: 'Permission Mode', description: 'Agent permission level selector', group: 'controls', icon: Shield, defaultVisible: true },
  { key: 'sound', label: 'Sound', description: 'Notification sound toggle', group: 'controls', icon: Volume2, defaultVisible: true },
  { key: 'sync', label: 'Sync', description: 'Multi-window sync toggle', group: 'controls', icon: ArrowUpDown, defaultVisible: true },
  { key: 'polling', label: 'Refresh', description: 'Background polling for updates', group: 'controls', icon: RefreshCw, defaultVisible: true },
  { key: 'tunnel', label: 'Remote', description: 'Remote control indicator', group: 'system', icon: Globe, defaultVisible: true },
  { key: 'version', label: 'Version', description: 'Update available indicator', group: 'system', icon: ArrowUpCircle, defaultVisible: true },
] as const;
```

The `useStatusBarVisibility` hook maps a `StatusBarItemKey` to the corresponding Zustand getter/setter pair:

```ts
/**
 * Bridge between a registry key and the Zustand store's showStatusBar* / setShowStatusBar* properties.
 *
 * @param key - Status bar item key from the registry
 * @returns Tuple of [isVisible, setVisible]
 */
export function useStatusBarVisibility(key: StatusBarItemKey): [boolean, (value: boolean) => void] {
  // Build the getter/setter property names from the key: 'cwd' -> 'showStatusBarCwd' / 'setShowStatusBarCwd'
  const capitalizedKey = key.charAt(0).toUpperCase() + key.slice(1);
  const showProp = `showStatusBar${capitalizedKey}` as keyof ReturnType<typeof useAppStore.getState>;
  const setProp = `setShowStatusBar${capitalizedKey}` as keyof ReturnType<typeof useAppStore.getState>;

  const visible = useAppStore((s) => s[showProp] as boolean);
  const setVisible = useAppStore((s) => s[setProp] as (v: boolean) => void);

  return [visible, setVisible];
}
```

The `resetStatusBarPreferences` function iterates the registry and resets only status bar toggles:

```ts
/**
 * Reset only status bar visibility preferences to their registry defaults.
 * Does NOT reset other preferences (font, theme, timestamps, etc.).
 */
export function resetStatusBarPreferences(): void {
  const store = useAppStore.getState();
  for (const item of STATUS_BAR_REGISTRY) {
    const capitalizedKey = item.key.charAt(0).toUpperCase() + item.key.slice(1);
    const setProp = `setShowStatusBar${capitalizedKey}` as keyof typeof store;
    const setter = store[setProp] as (v: boolean) => void;
    setter(item.defaultVisible);
  }
}
```

Also export a helper to get registry items grouped:

```ts
/** Return registry items grouped by their group field, in registry order. */
export function getGroupedRegistryItems(): { group: StatusBarItemGroup; label: string; items: StatusBarItemConfig[] }[] {
  const groups: StatusBarItemGroup[] = ['session', 'controls', 'system'];
  return groups
    .map((group) => ({
      group,
      label: GROUP_LABELS[group],
      items: STATUS_BAR_REGISTRY.filter((item) => item.group === group),
    }))
    .filter((g) => g.items.length > 0);
}
```

