## Step 2: Create responsive-popover.tsx

Create `apps/client/src/layers/shared/ui/responsive-popover.tsx`. This follows the exact same pattern as `responsive-dialog.tsx` (already in the codebase), but switches between Popover (desktop) and Sheet (mobile) instead of Dialog and Drawer.

```tsx
import * as React from 'react';
import { useIsMobile } from '../model';
import { Popover, PopoverTrigger, PopoverContent } from './popover';
import {
  Sheet,
  SheetTrigger,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
} from './sheet';
import { cn } from '../lib/utils';

interface ResponsivePopoverContextValue {
  isDesktop: boolean;
}

const ResponsivePopoverContext = React.createContext<ResponsivePopoverContextValue | undefined>(
  undefined
);

/** Read responsive popover context. Throws if used outside a ResponsivePopover. */
function useResponsivePopover(): ResponsivePopoverContextValue {
  const ctx = React.useContext(ResponsivePopoverContext);
  if (!ctx) {
    throw new Error('useResponsivePopover must be used within a <ResponsivePopover>');
  }
  return ctx;
}

interface ResponsivePopoverProps {
  children: React.ReactNode;
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
}

/** Renders a Popover on desktop or a bottom Sheet on mobile. */
function ResponsivePopover({ children, ...props }: ResponsivePopoverProps) {
  const isDesktop = !useIsMobile();
  const Comp = isDesktop ? Popover : Sheet;

  const ctxValue = React.useMemo<ResponsivePopoverContextValue>(
    () => ({ isDesktop }),
    [isDesktop]
  );

  return (
    <ResponsivePopoverContext.Provider value={ctxValue}>
      <Comp {...props}>{children}</Comp>
    </ResponsivePopoverContext.Provider>
  );
}
ResponsivePopover.displayName = 'ResponsivePopover';

/** Trigger that opens the responsive popover or sheet. */
function ResponsivePopoverTrigger({
  className,
  children,
  ...props
}: React.ComponentPropsWithoutRef<typeof PopoverTrigger>) {
  const { isDesktop } = useResponsivePopover();
  const Comp = isDesktop ? PopoverTrigger : SheetTrigger;
  return (
    <Comp className={className} {...props}>
      {children}
    </Comp>
  );
}
ResponsivePopoverTrigger.displayName = 'ResponsivePopoverTrigger';

/** Content panel — Popover on desktop, bottom Sheet on mobile. */
function ResponsivePopoverContent({
  className,
  children,
  side,
  align,
  ...props
}: React.ComponentPropsWithoutRef<typeof PopoverContent> & { side?: string; align?: string }) {
  const { isDesktop } = useResponsivePopover();
  if (isDesktop) {
    return (
      <PopoverContent
        side={side as 'top' | 'bottom' | 'left' | 'right'}
        align={align as 'start' | 'center' | 'end'}
        className={cn('w-80', className)}
        {...props}
      >
        {children}
      </PopoverContent>
    );
  }
  return (
    <SheetContent side="bottom" className={cn('flex max-h-[80vh] flex-col', className)} {...props}>
      {children}
    </SheetContent>
  );
}
ResponsivePopoverContent.displayName = 'ResponsivePopoverContent';

/** Title shown only in the Sheet variant (mobile). Returns null on desktop. */
function ResponsivePopoverTitle({
  className,
  children,
  ...props
}: React.HTMLAttributes<HTMLHeadingElement>) {
  const { isDesktop } = useResponsivePopover();
  if (isDesktop) return null;
  return (
    <SheetHeader>
      <SheetTitle className={className} {...props}>
        {children}
      </SheetTitle>
    </SheetHeader>
  );
}
ResponsivePopoverTitle.displayName = 'ResponsivePopoverTitle';

export {
  ResponsivePopover,
  ResponsivePopoverTrigger,
  ResponsivePopoverContent,
  ResponsivePopoverTitle,
  useResponsivePopover,
};
```

