Create the shared toggle list content component and the responsive popover wrapper that displays the configure UI.

## Files to Create

### `apps/client/src/layers/features/status/ui/StatusBarConfigureContent.tsx`

This component renders the grouped toggle list used by both the Popover (desktop) and Sheet (mobile). It is a pure presentation component that reads from the registry and Zustand store.

```tsx
import {
  STATUS_BAR_REGISTRY,
  getGroupedRegistryItems,
  useStatusBarVisibility,
  resetStatusBarPreferences,
} from '../model/status-bar-registry';
import type { StatusBarItemConfig } from '../model/status-bar-registry';
import { SettingRow, Switch } from '@/layers/shared/ui';

/** Single toggle row for a status bar item. */
function StatusBarToggleRow({ item }: { item: StatusBarItemConfig }) {
  const [visible, setVisible] = useStatusBarVisibility(item.key);
  const Icon = item.icon;

  return (
    <SettingRow
      label={
        <span className="inline-flex items-center gap-2">
          <Icon className="text-muted-foreground size-3.5" />
          {item.label}
        </span>
      }
      description={item.description}
    >
      <Switch checked={visible} onCheckedChange={setVisible} />
    </SettingRow>
  );
}

/**
 * Grouped toggle list for configuring status bar item visibility.
 * Shared content rendered by both the desktop Popover and mobile Sheet.
 */
export function StatusBarConfigureContent() {
  const groups = getGroupedRegistryItems();

  return (
    <div className="space-y-4">
      <p className="text-muted-foreground text-xs font-medium uppercase tracking-wide">
        Status Bar Items
      </p>
      {groups.map((group) => (
        <div key={group.group} className="space-y-1">
          <p className="text-muted-foreground text-xs font-medium uppercase tracking-wide">
            {group.label}
          </p>
          <div className="space-y-0">
            {group.items.map((item) => (
              <StatusBarToggleRow key={item.key} item={item} />
            ))}
          </div>
        </div>
      ))}
      <div className="border-border border-t pt-2">
        <button
          type="button"
          onClick={resetStatusBarPreferences}
          className="text-muted-foreground hover:text-foreground text-xs transition-colors duration-150"
        >
          Reset to defaults
        </button>
      </div>
    </div>
  );
}
```

Note: The `SettingRow` component accepts a `label` prop as `string`. If the existing `SettingRow` only supports `string` labels, the icon will need to be rendered differently (e.g., a separate icon column before the SettingRow, or the SettingRow label prop updated to accept `ReactNode`). Check the current `SettingRow` implementation — if `label` is typed as `string`, either:
- Update `SettingRow` to accept `ReactNode` for label (preferred, minimal change)
- Or render the icon as a separate element before the SettingRow

