### `apps/client/src/layers/features/status/ui/StatusBarConfigurePopover.tsx`

Responsive wrapper that renders Popover on desktop and Sheet on mobile:

```tsx
import {
  ResponsivePopover,
  ResponsivePopoverTrigger,
  ResponsivePopoverContent,
  ResponsivePopoverTitle,
} from '@/layers/shared/ui';
import { StatusBarConfigureContent } from './StatusBarConfigureContent';

interface StatusBarConfigurePopoverProps {
  children: React.ReactNode; // The trigger element (configure icon)
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
}

/**
 * Configure popover/sheet for status bar item visibility.
 * Renders as an upward Popover on desktop, bottom Sheet on mobile.
 */
export function StatusBarConfigurePopover({
  children,
  open,
  onOpenChange,
}: StatusBarConfigurePopoverProps) {
  return (
    <ResponsivePopover open={open} onOpenChange={onOpenChange}>
      <ResponsivePopoverTrigger asChild>{children}</ResponsivePopoverTrigger>
      <ResponsivePopoverContent
        side="top"
        align="end"
        className="max-h-[70vh] w-80 overflow-y-auto p-4"
        aria-label="Status bar configuration"
      >
        <ResponsivePopoverTitle>Configure Status Bar</ResponsivePopoverTitle>
        <StatusBarConfigureContent />
      </ResponsivePopoverContent>
    </ResponsivePopover>
  );
}
```

