## Accessibility Verification

Verify these requirements are met (fix if not):

1. **Configure icon**: Has `aria-label="Configure status bar"` and `role="button"` (implicit from `<button>` element)
2. **Popover**: Has `aria-label="Status bar configuration"` on the content container
3. **Toggle switches**: Already accessible via `SettingRow` + `Switch` (Radix Switch has proper ARIA role="switch" and aria-checked)
4. **Context menu**: shadcn `ContextMenu` provides `role="menu"`, `role="menuitem"`, keyboard navigation (arrow keys, Enter/Space, Escape)
5. **Keyboard access to context menu**: Verify that Shift+F10 or the context menu key works when a status bar item is focused. This is provided by the browser and shadcn's ContextMenu Radix primitive — no custom code needed, but verify in tests.
6. **Group headers in popover**: Rendered as visual labels with appropriate ARIA treatment. Use `role="separator"` or simply rely on the visual hierarchy since they're not interactive elements.
7. **Focus trap in popover**: Radix Popover provides focus trapping by default. Verify the popover traps focus when opened and returns focus to the trigger on close.

## Integration Tests

Create `apps/client/src/layers/features/status/__tests__/status-bar-integration.test.tsx`:

```tsx
/**
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import '@testing-library/jest-dom';
import { STATUS_BAR_REGISTRY } from '../model/status-bar-registry';
import { useAppStore } from '@/layers/shared/model';

describe('Status bar inline management integration', () => {
  beforeEach(() => {
    // Reset all status bar visibility to defaults
    const store = useAppStore.getState();
    for (const item of STATUS_BAR_REGISTRY) {
      const capitalizedKey = item.key.charAt(0).toUpperCase() + item.key.slice(1);
      const setProp = `setShowStatusBar${capitalizedKey}`;
      (store as Record<string, unknown>)[setProp]?.(item.defaultVisible);
    }
  });

  it('registry covers all showStatusBar* store properties', () => {
    const store = useAppStore.getState();
    const storeKeys = Object.keys(store)
      .filter((k) => k.startsWith('showStatusBar') && !k.startsWith('setShowStatusBar'))
      .map((k) => k.replace('showStatusBar', ''))
      .map((k) => k.charAt(0).toLowerCase() + k.slice(1));

    const registryKeys = STATUS_BAR_REGISTRY.map((item) => item.key);

    // Every store key should be in the registry
    for (const storeKey of storeKeys) {
      expect(registryKeys).toContain(storeKey);
    }
  });

  it('every registry key has a corresponding store getter and setter', () => {
    const store = useAppStore.getState();
    for (const item of STATUS_BAR_REGISTRY) {
      const capitalizedKey = item.key.charAt(0).toUpperCase() + item.key.slice(1);
      const showProp = `showStatusBar${capitalizedKey}`;
      const setProp = `setShowStatusBar${capitalizedKey}`;

      expect(typeof (store as Record<string, unknown>)[showProp]).toBe('boolean');
      expect(typeof (store as Record<string, unknown>)[setProp]).toBe('function');
    }
  });

  it('resetStatusBarPreferences only resets status bar toggles', () => {
    const { resetStatusBarPreferences } = require('../model/status-bar-registry');
    const store = useAppStore.getState();

    // Change a status bar preference
    store.setShowStatusBarCwd(false);
    // Change a non-status-bar preference
    store.setShowTimestamps(true);

    resetStatusBarPreferences();

    // Status bar pref should be reset
    expect(useAppStore.getState().showStatusBarCwd).toBe(true);
    // Non-status-bar pref should be unchanged
    expect(useAppStore.getState().showTimestamps).toBe(true);
  });

  it('registry defaultVisible values match store BOOL_DEFAULTS', () => {
    // All current items default to true
    for (const item of STATUS_BAR_REGISTRY) {
      expect(item.defaultVisible).toBe(true);
    }
  });
});
```

